 // src/pages/DashboardHome.js
import React, { useEffect, useState, useCallback, useRef } from 'react';
import Charts from '../components/Charts';
import StatCard from '../components/StatCard';
import api from '../services/api';
import WebSocketService from '../services/WebSocketService';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';


// ✅ Fix default Leaflet marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';


delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});


const DashboardHome = () => {
  const [vehicleStats, setVehicleStats] = useState({
    total: 0,
    active: 0,
    idle: 0,
    maintenance: 0,
  });
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [retryCount, setRetryCount] = useState(0);
  const wsConnectedRef = useRef(false);
  const maxRetries = 3;


  // ✅ Calculate stats from vehicles data
  const calculateStats = useCallback((vehicleData) => {
    return {
      total: vehicleData.length,
      active: vehicleData.filter(v => v.status === 'ACTIVE').length,
      idle: vehicleData.filter(v => v.status === 'IDLE').length,
      maintenance: vehicleData.filter(v => v.status === 'MAINTENANCE').length,
    };
  }, []);


  // ✅ Fetch initial vehicle data with authentication handling
  const fetchVehicleData = useCallback(async () => {
    try {
      setError(null);
      const data = await api.getVehicles();
      
      if (Array.isArray(data)) {
        setVehicles(data);
        setVehicleStats(calculateStats(data));
        setRetryCount(0); // Reset retry count on success
      } else {
        throw new Error('Invalid data format received');
      }
    } catch (err) {
      console.error('Error fetching vehicle data:', err);
      
      // Handle authentication errors specifically
      if (err.response?.status === 401 || err.response?.status === 403) {
        setError('Authentication failed. Please log in again.');
        // Clear invalid tokens
        localStorage.removeItem('token');
        sessionStorage.removeItem('token');
        window.location.href = '/login';
        return;
      }
      
      // Handle other errors with retry logic
      if (retryCount < maxRetries) {
        setError(`Failed to load data. Retrying... (${retryCount + 1}/${maxRetries})`);
        setRetryCount(prev => prev + 1);
        setTimeout(fetchVehicleData, 2000 * (retryCount + 1)); // Exponential backoff
      } else {
        setError('Failed to load vehicle data. Please refresh the page.');
      }
    } finally {
      setLoading(false);
    }
  }, [calculateStats, retryCount, maxRetries]);


  // ✅ Handle WebSocket vehicle updates
  const handleVehicleUpdate = useCallback((vehicleData) => {
    try {
      setVehicles(prevVehicles => {
        const updatedVehicles = prevVehicles.filter(v => v.id !== vehicleData.id);
        const newVehicles = [...updatedVehicles, vehicleData];
        
        // Update stats with new vehicle data
        setVehicleStats(calculateStats(newVehicles));
        
        return newVehicles;
      });
    } catch (err) {
      console.error('Error processing vehicle update:', err);
    }
  }, [calculateStats]);


  // ✅ Initial data fetch
  useEffect(() => {
    fetchVehicleData();
  }, []); // Remove fetchVehicleData from deps to prevent infinite loop


  // ✅ WebSocket connection with proper cleanup
  useEffect(() => {
    let wsCleanup = null;


    const connectWebSocket = () => {
      try {
        WebSocketService.connect(() => {
          console.log('WebSocket connected successfully');
          wsConnectedRef.current = true;
          
          // Subscribe to vehicle updates
          WebSocketService.subscribe('/topic/vehicles', handleVehicleUpdate);
          
          // Subscribe to alerts if needed
          WebSocketService.subscribe('/topic/alerts', (alertData) => {
            console.log('New alert received:', alertData);
            // Handle alert updates here if needed
          });
        });


        // Set up cleanup function
        wsCleanup = () => {
          console.log('Cleaning up WebSocket connection');
          wsConnectedRef.current = false;
          WebSocketService.disconnect();
        };


      } catch (err) {
        console.error('WebSocket connection failed:', err);
        wsConnectedRef.current = false;
      }
    };


    // Only connect if not already connected
    if (!wsConnectedRef.current) {
      connectWebSocket();
    }


    // Return cleanup function
    return () => {
      if (wsCleanup) {
        wsCleanup();
      }
    };
  }, [handleVehicleUpdate]);


  // ✅ Map center with fallback
  const mapCenter = vehicles.length > 0
    ? [vehicles[0].lat || 20.5937, vehicles[0].lng || 78.9629]
    : [20.5937, 78.9629]; // Default India center


  // ✅ Error display component
  const ErrorDisplay = ({ message, onRetry }) => (
    <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center">
          <div className="text-red-400 mr-2">⚠️</div>
          <p className="text-red-700 text-sm">{message}</p>
        </div>
        {onRetry && (
          <button
            onClick={onRetry}
            className="bg-red-600 text-white px-3 py-1 rounded text-sm hover:bg-red-700 transition"
          >
            Retry
          </button>
        )}
      </div>
    </div>
  );


  // ✅ Loading state
  if (loading) {
    return (
      <div className="space-y-6">
        <h2 className="g-title">Dashboard Home</h2>
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
          <p className="ml-4 text-gray-600">Loading dashboard data...</p>
        </div>
      </div>
    );
  }


  return (
    <div className="space-y-6">
      <h2 className="g-title">Dashboard Home</h2>


      {/* Error Display */}
      {error && (
        <ErrorDisplay 
          message={error} 
          onRetry={retryCount < maxRetries ? () => {
            setError(null);
            setLoading(true);
            fetchVehicleData();
          } : null}
        />
      )}


      {/* ✅ REMOVED: Connection Status Section - No longer shows WebSocket status */}


      {/* Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Vehicles" 
          value={vehicleStats.total} 
          color="blue" 
          loading={false}
        />
        <StatCard 
          title="Active Vehicles" 
          value={vehicleStats.active} 
          color="green" 
          loading={false}
        />
        <StatCard 
          title="Idle Vehicles" 
          value={vehicleStats.idle} 
          color="yellow" 
          loading={false}
        />
        <StatCard 
          title="Maintenance" 
          value={vehicleStats.maintenance} 
          color="red" 
          loading={false}
        />
      </div>


      {/* Charts & Map */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Vehicle Status Chart */}
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Status Distribution</h3>
          {vehicles.length > 0 ? (
            <Charts
              type="doughnut"
              data={{
                labels: ['Active', 'Idle', 'Maintenance'],
                datasets: [
                  {
                    data: [vehicleStats.active, vehicleStats.idle, vehicleStats.maintenance],
                    backgroundColor: ['#22c55e', '#facc15', '#ef4444'],
                    borderWidth: 2,
                    borderColor: '#ffffff',
                  },
                ],
              }}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: 'bottom',
                  },
                },
              }}
            />
          ) : (
            <div className="flex items-center justify-center h-64 text-gray-500">
              No vehicle data available
            </div>
          )}
        </div>


        {/* Live Vehicle Map */}
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">
            Live Vehicle Locations ({vehicles.length} vehicles)
          </h3>
          {vehicles.length > 0 ? (
            <div className="w-full h-[400px] rounded-lg overflow-hidden">
              <MapContainer 
                center={mapCenter} 
                zoom={vehicles.length === 1 ? 10 : 5} 
                className="w-full h-full"
                key={`map-${vehicles.length}`} // Force re-render when vehicles change
              >
                <TileLayer
                  attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> contributors'
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />
                {vehicles.map(vehicle => (
                  vehicle.lat && vehicle.lng ? (
                    <Marker 
                      key={`vehicle-${vehicle.id}`} 
                      position={[vehicle.lat, vehicle.lng]}
                    >
                      <Popup>
                        <div className="text-sm">
                          <strong>🚗 Vehicle {vehicle.id}</strong><br />
                          Status: <span className={`font-medium ${
                            vehicle.status === 'ACTIVE' ? 'text-green-600' : 
                            vehicle.status === 'IDLE' ? 'text-yellow-600' : 
                            'text-red-600'
                          }`}>
                            {vehicle.status}
                          </span><br />
                          {vehicle.speed && <span>Speed: {vehicle.speed} km/h<br /></span>}
                          {vehicle.driver && <span>Driver: {vehicle.driver}</span>}
                        </div>
                      </Popup>
                    </Marker>
                  ) : null
                ))}
              </MapContainer>
            </div>
          ) : (
            <div className="flex items-center justify-center h-[400px] bg-gray-100 rounded-lg text-gray-500">
              <div className="text-center">
                <div className="text-4xl mb-2">🗺️</div>
                <p>No vehicle location data available</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};


export default DashboardHome;
